	@Test
	void closeIsIdempotentAndDropsRetainedDistinctState() {
		RecordingPlan plan = new RecordingPlan(2);
		NativeRowsStep step = new NativeRowsStep(null, plan, NativeSlotLayout.empty(), new int[0], new String[0],
				true, new int[0], new boolean[0], 0, -1, true, null, null, null, Set.of(), null, null);
		NativeRowsIteration iteration = (NativeRowsIteration) step.evaluate(EmptyBindingSet.getInstance());

		assertThat(iteration.hasNext()).isTrue();
		assertThat(iteration.distinctRows.emptySeen).isTrue();

		iteration.close();
		iteration.close();

		assertThat(iteration.hasNext()).isFalse();
		assertThat(iteration.distinctRows).as("DISTINCT tuple state is released on close").isNull();
		assertThat(iteration.cursor).as("active cursor is released on close").isNull();
		assertThat(iteration.base).as("incoming bindings are released on close").isNull();
		assertThat(iteration.step).as("compiled step is released on close").isNull();
		assertThat(plan.nextCalls).as("close does not enumerate remaining rows").isOne();
		assertThat(plan.closeCalls).as("cursor close is idempotent").isOne();
	}

	@Test
	void factorizedFirstResultDoesNotProjectRemainingCartesianProduct() {
		RecordingNativeSource source = new RecordingNativeSource();
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("s1", 0, "o1", 1, "s2", 2, "o2", 3), null);
		layout.freeze(List.of("s1", "o1", "s2", "o2"));
		PatternPlan left = pattern(0, P1, 1);
		PatternPlan right = pattern(2, P2, 3);
		MultiJoinPlan join = new MultiJoinPlan(new SlotPlan[] { left, right }, new MaskedFilter[0]);
		NativeRowsStep step = new NativeRowsStep(source, join, layout, new int[] { 0, 1, 2, 3 },
				new String[] { "s1", "o1", "s2", "o2" }, false, new int[0], new boolean[0], 0, -1, true,
				null, null, null, Set.of(), null, null);
		long engagements = LmdbNativeFactorizedRows.ENGAGED.get();

		try (CloseableIteration<BindingSet> iteration = step.evaluate(EmptyBindingSet.getInstance())) {
			assertThat(source.statementCalls).as("factorized scans before iteration demand").hasValue(0);
			assertThat(iteration.hasNext()).isTrue();
			assertThat(LmdbNativeFactorizedRows.ENGAGED.get()).isEqualTo(engagements + 1);
			assertThat(source.statementCalls).as("each independent tail branch scans once").hasValue(2);
			assertThat(source.lazyValueCalls).as("projection keeps the first row as native ids").hasValue(0);
			assertThat(iteration.next()).hasSize(4);
			assertThat(source.lazyValueCalls).as("inspecting that row materializes only its four values").hasValue(4);
		}

		assertThat(source.closedIterators).as("retained tail probes close on early result close").hasValue(2);
	}

	@Test
	void failedChunkFactorizedAttemptDoesNotCommitCountersOrStrategy() {
		IOException failure = new IOException("synthetic first chunk scan failure");
		RecordingNativeSource source = new RecordingNativeSource(failure);
		NativeSlotLayout layout = new NativeSlotLayout(
				Map.of("root", 0, "middle", 1, "leaf", 2, "unprojectedTail", 3), null);
		layout.freeze(List.of("root", "middle", "leaf", "unprojectedTail"));
		PatternPlan root = new PatternPlan(Term.slot(0), Term.constant(P1), Term.slot(1), Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, 1);
		PatternPlan middle = new PatternPlan(Term.slot(1), Term.constant(P2), Term.slot(2), Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, 2);
		PatternPlan tail = new PatternPlan(Term.slot(2), Term.constant(P3), Term.slot(3), Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, 3);
		MultiJoinPlan join = new MultiJoinPlan(new SlotPlan[] { root, middle, tail }, new MaskedFilter[0]);
		SingletonSet telemetry = new SingletonSet();
		telemetry.setRuntimeTelemetryEnabled(true);
		NativeRowsStep step = new NativeRowsStep(source, join, layout, new int[] { 0, 2 },
				new String[] { "root", "leaf" }, false, new int[0], new boolean[0], 0, -1, true,
				null, telemetry, null, Set.of(), null, null);
		long factorizedBefore = LmdbNativeFactorizedRows.ENGAGED.get();
		long chunkBefore = LmdbNativeChunkPipeline.ENGAGED.get();

		try (CloseableIteration<BindingSet> iteration = step.evaluate(EmptyBindingSet.getInstance())) {
			assertThatThrownBy(iteration::hasNext)
					.isInstanceOf(QueryEvaluationException.class)
					.hasCause(failure);
		}

		assertThat(LmdbNativeFactorizedRows.ENGAGED.get())
				.as("an attempt that fails before producing its first row must not claim factorized engagement")
				.isEqualTo(factorizedBefore);
		assertThat(LmdbNativeChunkPipeline.ENGAGED.get())
				.as("an attempt that fails on its first prefix fill must not claim chunk engagement")
				.isEqualTo(chunkBefore);
		assertThat(telemetry.getStringMetricActual(LmdbNativeExplain.EXECUTION_PATH))
				.as("failed speculative execution must not report the chunk/factorized strategy")
				.isNull();
	}

